form:Form.form:Scripts:
		function parentesco_onvalidate(pObj)
{  
  if (Ctrl("oi_tipo_familiar").GetCValue() == "99 - A CARGO DE SEGURO DE VIDA" && pObj.GetCValue() == "")
	{
		pObj.SetError("El campo parentesco es requerido para el tipo de familiar 99.");		
		return false;
	}
	return true;	
}


function porc_seguro_onvalidate(pObj)
{	
	if (Ctrl("l_acargo_SV").GetCValue() == "1" && pObj.GetCValue() == "")
	{		
		pObj.SetError("El campo porcentaje es requerido.");
		return false;
	}	
	return true;	
}


function acargo_SV_onclick()
{ 
	//Ctrl("n_porc_seguro").SetCValue("");
  if (Ctrl("l_acargo_SV").GetCValue() == "1")
  {    
    CtrlEnabled("n_porc_seguro", true);
  }
  else
  {
  	Ctrl("n_porc_seguro").SetCValue("");
		CtrlEnabled("n_porc_seguro", false);		  
  }
}


function tipo_familiar_onchange()
{
	Ctrl("d_parentesco").SetCValue("");	
	if (Ctrl("oi_tipo_familiar").GetCValue() == "99 - A CARGO DE SEGURO DE VIDA")
	{		
		CtrlEnabled("d_parentesco", true);
		Ctrl("l_acargo_SV").SetCValue("1");
		CtrlEnabled("l_acargo_SV", false);
		CtrlEnabled("n_porc_seguro", true);
	}
	else
	{	 	
		CtrlEnabled("d_parentesco", false);
		//Ctrl("l_acargo_SV").SetCValue("0");
		CtrlEnabled("l_acargo_SV", true);		
		//CtrlEnabled("n_porc_seguro", false);		
	}
}


function nombreyapellido ()
{
	Ctrl('d_ape_y_nom').SetCValue(Ctrl('d_apellido').GetCValue()+', '+Ctrl('d_nombres').GetCValue());		
}

function val_f_nacimiento(Me)
{	
	if (Me.TypedValue() != null && Me.TypedValue() > NowDate())
	{
		Me.SetError('La fecha de Nacimiento debe ser anterior a la Fecha Actual');
		return false;
	}	
	return true;
}

function val_f_fallecimiento(Me)
{
	if (Me.TypedValue() != null && Me.TypedValue() > NowDate())
	{
		Me.SetError('La fecha de Fallecimiento debe ser anterior a la Fecha Actual');
		return false;
	}

	if (Me.TypedValue() != null && Ctrl('l_vive').TypedValue() == true)
	{
		Me.SetError('Si la Fecha de Fallecimiento no es vacia, el campo Vive no debe estar chequeado');
		return false;
	}

	if (Me.GetXValue() != null && Ctrl('f_nacimiento').GetXValue != null && Me.GetXValue() > Ctrl('f_nacimiento').GetXValue)
	{
		Me.SetError('La fecha de Nacimiento debe ser anterior a la fecha de Fallecimiento');
		return false;
	}

	return true;
}

function val_e_anio_inic_esc(Me)
{
	if (Me.TypedValue() != null && Me.TypedValue() > NowDate().getFullYear())
	{
		Me.SetError('El año de Iniciacion Escolar debe ser menor o igual al año Actual');
		return false;
	}
	else
		return true;
}

function val_e_anio_fin_esc(Me) //as boolean(NCTextBox)
{  
	if (Me.TypedValue() != null && Me.TypedValue() > NowDate().getFullYear())
	{
		Me.SetError('El año de Finalizacion Escolar debe ser menor o igual al año Actual');
		return false;
	}

	if (Me.TypedValue() != null && Ctrl('e_anio_inic_esc').TypedValue() != null && Me.TypedValue() < Ctrl('e_anio_inic_esc').TypedValue())
	{
		Me.SetError('El año Finalizacion Escolar debe ser mayor al año Iniciacion Escolar');
		return false;
	}			
	return true;					
}

function val_f_hasta_IG(Me)
{
	if (Me.TypedValue() != null && Ctrl('f_desde_IG').TypedValue() != null && Me.TypedValue() <= Ctrl('f_desde_IG').TypedValue())
	{
		Me.SetError('La fecha hasta IG debe ser posterior a la fecha desde IG');
		return false;
	}
	else
		return true;						
}
